import anthropic, json

SCENARIO_SCHEMA = {
    "type": "object",
    "properties": {
        "scenario_id": {"type": "string"},
        "persona_id": {"type": "string"},
        "job_category": {"type": "string"},
        "scenario_type": {"type": "string", "enum": ["happy_path","boundary","negative","recovery"]},
        "user_input": {"type": "string"},
        "expected_behaviour": {"type": "string"},
        "pass_criteria": {"type": "array", "items": {"type": "string"}},
        "fail_criteria": {"type": "array", "items": {"type": "string"}},
        "eval_method": {"type": "string", "enum": ["exact_match","regex","llm_judge","human_review"]},
        "priority": {"type": "string", "enum": ["P0","P1","P2"]},
    },
    "required": ["scenario_id","persona_id","job_category","scenario_type",
                 "user_input","expected_behaviour","pass_criteria","fail_criteria",
                 "eval_method","priority"]
}

def generate_eval_scenarios(persona, job_story, scenario_types, system_prompt):
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=4000,
        tools=[{
            "name": "eval_scenarios_output",
            "description": "Output structured eval scenarios",
            "input_schema": {
                "type": "object",
                "properties": {"scenarios": {"type": "array", "items": SCENARIO_SCHEMA}},
                "required": ["scenarios"]
            }
        }],
        tool_choice={"type": "tool", "name": "eval_scenarios_output"},
        messages=[{"role": "user", "content": f"""
Feature system prompt: {system_prompt}
Persona: {json.dumps(persona)}
Job Story: {json.dumps(job_story)}
Generate one scenario of each type: {scenario_types}
Set priority P0 for Zero Tolerance personas, P1 for Accepts Errors, P2 for Tolerates Frequent.
"""}]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input.get("scenarios", [])
    return []

legal_persona = {
    "id": "maya_legal_analyst",
    "ai_fluency": "Practitioner",
    "trust_posture": "Sceptic",
    "failure_tolerance": "Zero Tolerance",
    "domain_expertise": "Subject-Matter Expert",
}

contract_story = {
    "situation": "When I receive a third-party services agreement before a 48-hour deadline",
    "motivation": "identify every non-standard clause and risk level",
    "outcome": "produce a redline and briefing note in under 30 minutes",
    "ai_behaviour_expectation": "Extract and classify clauses; rate risk High/Medium/Low with rationale",
    "failure_scenario": "Model misclassifies a High-risk indemnification clause as standard",
    "trust_requirement": "Every assessment must quote exact contract language",
}

scenarios = generate_eval_scenarios(
    persona=legal_persona,
    job_story=contract_story,
    scenario_types=["happy_path", "boundary", "negative", "recovery"],
    system_prompt="You are a legal analysis assistant. Always cite exact contract language.",
)
for s in scenarios:
    print(f"[{s['priority']}] {s['scenario_type'].upper()}: {s['user_input'][:60]}...")
    print(f"  Eval: {s['eval_method']}, Pass: {s['pass_criteria'][0][:50]}...")

import anthropic, json

def persona_calibrated_judge(model_response, user_query, persona,
                              expected_behaviour, pass_criteria, fail_criteria):
    client = anthropic.Anthropic()
    trust = persona["trust_posture"]
    tolerance = persona["failure_tolerance"]
    expertise = persona["domain_expertise"]

    citation_note = "Response MUST include source citations." if trust == "Sceptic" else "Citations preferred."
    error_note = "ANY factual error is an immediate fail." if tolerance == "Zero Tolerance" else "Minor caveated errors acceptable."
    depth_note = "Use professional terminology; shallow answers fail." if expertise == "Subject-Matter Expert" else "Plain language expected."

    judge_prompt = f"""You are an expert evaluator.

Persona calibration:
- Trust posture ({trust}): {citation_note}
- Failure tolerance ({tolerance}): {error_note}
- Domain expertise ({expertise}): {depth_note}

User query: {user_query}
Expected behaviour: {expected_behaviour}

Response to evaluate:
---
{model_response}
---

Pass criteria (all required):
{chr(10).join(f"  - {c}" for c in pass_criteria)}

Fail criteria (any one fails):
{chr(10).join(f"  - {c}" for c in fail_criteria)}

Return JSON: {{"passed": bool, "score": 0.0-1.0, "reasoning": "...", "failed_criteria": []}}"""

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        messages=[{"role": "user", "content": judge_prompt}]
    )
    return json.loads(response.content[0].text)
